class Solution {
    public int numberOfArrays(String s, int k) {
        int MOD = (int) (1e9 + 7);
        int n = s.length();
        long[] dp = new long[n + 1];
        dp[0] = 1;
        for (int i = 1; i <= n; i++) {
            long cur = 0;
            for (int j = i; j >= 1 && i - j + 1 <= String.valueOf(k).length(); j--) {
                if (s.charAt(j - 1) == '0') break;
                long num = Long.parseLong(s.substring(j - 1, i));
                if (num <= k) cur = (cur + dp[j - 1]) % MOD;
            }
            dp[i] = cur;
        }
        return (int) dp[n];
    }
}
efficiency: HIGH
time complexity: O(n * log(k))
space complexity: O(n)
